class Solution:
    def countVowels(self, word):
        """
        :type word: str
        :rtype: int
        """
        vowels = set('aeiou')
        total = 0

        # For each vowel at position i, it contributes to (i+1)*(n-i) substrings
        for i in range(len(word)):
            if word[i] in vowels:
                total += (i + 1) * (len(word) - i)

        return total
